/* ══════════════════════════════════════════════════════════════
   TRC² — site interactions
   ══════════════════════════════════════════════════════════════ */

// ══════════ THEME HELPER ══════════
const TRC_THEME = {
  get isDark(){return document.documentElement.getAttribute('data-theme')==='dark';},
  get axisInk(){return this.isDark?'rgba(255,255,255,.6)':'rgba(0,0,0,.65)';},
  get axisFaint(){return this.isDark?'rgba(255,255,255,.32)':'rgba(0,0,0,.45)';},
  get grid(){return this.isDark?'rgba(255,255,255,.08)':'rgba(0,0,0,.08)';},
  get gridFaint(){return this.isDark?'rgba(255,255,255,.04)':'rgba(0,0,0,.04)';},
  get plotBg(){return this.isDark?'rgba(0,0,0,.4)':'rgba(255,255,255,.5)';},
  get cortexLine(){return this.isDark?'rgba(96,165,250,.12)':'rgba(37,99,235,.18)';},
  get cortex(){return this.isDark?'96,165,250':'37,99,235';},
  get thalamus(){return this.isDark?'251,191,36':'180,83,9';},
  get hippo(){return this.isDark?'192,132,252':'124,58,237';},
  get replay(){return this.isDark?'52,211,153':'4,120,87';},
  get gate(){return this.isDark?'244,114,182':'190,24,93';},
  get trc(){return this.isDark?'255,59,59':'225,29,46';},
};
window.TRC_THEME = TRC_THEME;

// ══════════ THEME TOGGLE ══════════
(()=>{
  const btn=document.getElementById('themeToggle');
  if(!btn)return;
  btn.addEventListener('click',()=>{
    const cur=document.documentElement.getAttribute('data-theme')||'light';
    const nxt=cur==='dark'?'light':'dark';
    document.documentElement.setAttribute('data-theme',nxt);
    localStorage.setItem('trc2-theme',nxt);
    window.dispatchEvent(new Event('themechange'));
  });
})();

// ══════════ CUSTOM CURSOR + TRAIL ══════════
(() => {
  const cur = document.getElementById('cur'), curR = document.getElementById('curR');
  let mx=innerWidth/2,my=innerHeight/2,rx=mx,ry=my;
  addEventListener('mousemove',e=>{
    mx=e.clientX;my=e.clientY;
    cur.style.left=mx+'px';cur.style.top=my+'px';
    if(Math.random()<.35){
      const t=document.createElement('div');t.className='cursor-trail';
      t.style.left=mx+'px';t.style.top=my+'px';
      document.body.appendChild(t);
      t.animate([{opacity:.6,transform:'translate(-50%,-50%) scale(1)'},{opacity:0,transform:'translate(-50%,-50%) scale(.2)'}],{duration:700,easing:'ease-out'}).onfinish=()=>t.remove();
    }
  });
  (function loop(){rx+=(mx-rx)*.18;ry+=(my-ry)*.18;curR.style.left=rx+'px';curR.style.top=ry+'px';requestAnimationFrame(loop);})();
  document.querySelectorAll('a,button,.chip,.obtn,.knob,.rm-row,.stream-bar').forEach(el=>{
    el.addEventListener('mouseenter',()=>curR.classList.add('hot'));
    el.addEventListener('mouseleave',()=>curR.classList.remove('hot'));
  });
})();

// ══════════ TOPBAR + REVEAL ══════════
(() => {
  const tb=document.getElementById('topbar');
  addEventListener('scroll',()=>tb.classList.toggle('scrolled',scrollY>20));
  const io=new IntersectionObserver(es=>es.forEach(e=>e.isIntersecting&&e.target.classList.add('in')),{threshold:.12});
  document.querySelectorAll('.reveal').forEach(el=>io.observe(el));
})();

/* ══════════════════════════════════════════════════════════════
   HERO · BRAIN NETWORK (canvas 2D, not WebGL — runs everywhere)
   Three floating modules: cortex grid, thalamus hub, hippocampus
   Pulses travel the thalamo-cortical & hippo-cortical loops.
   ══════════════════════════════════════════════════════════════ */
(() => {
  const c=document.getElementById('brainCanvas'),ctx=c.getContext('2d');
  let w,h,dpr,t=0;
  function resize(){
    dpr=Math.min(2,devicePixelRatio||1);
    w=c.offsetWidth;h=c.offsetHeight;
    c.width=w*dpr;c.height=h*dpr;
    ctx.setTransform(dpr,0,0,dpr,0,0);
  }
  addEventListener('resize',resize);resize();

  // Cortex column grid — 6 columns × 4 layers of nodes
  const cols=6,rows=4;
  const cortexNodes=[];
  function layoutCortex(){
    cortexNodes.length=0;
    const cx=w*.62,cy=h*.5;
    const gw=Math.min(w*.34,460),gh=Math.min(h*.55,340);
    for(let y=0;y<rows;y++)for(let x=0;x<cols;x++){
      cortexNodes.push({
        x: cx - gw/2 + (x/(cols-1))*gw,
        y: cy - gh/2 + (y/(rows-1))*gh,
        col:x, row:y,
        base:.3+Math.random()*.4,
        phase:Math.random()*Math.PI*2,
      });
    }
  }
  layoutCortex();

  // Thalamus hub — amber ring
  function thal(){return{x:w*.28,y:h*.48,r:Math.min(w,h)*.075};}
  // Hippocampus — violet arc
  function hippo(){return{x:w*.28,y:h*.72,r:Math.min(w,h)*.055};}

  // Pulses travelling loops
  const pulses=[];
  function spawnPulse(type){
    // type: 'thal2ctx' | 'ctx2thal' | 'hippo2ctx' | 'ctx2hippo' | 'replay'
    pulses.push({type,t:0,speed:.004+Math.random()*.004,seed:Math.random()});
  }
  setInterval(()=>spawnPulse('thal2ctx'),320);
  setInterval(()=>spawnPulse('ctx2thal'),280);
  setInterval(()=>spawnPulse('hippo2ctx'),520);
  setInterval(()=>spawnPulse('ctx2hippo'),640);
  setInterval(()=>spawnPulse('replay'),900);

  function lerp(a,b,k){return a+(b-a)*k;}
  function pathPoint(type,p){
    const T=thal(),H=hippo();
    const target=cortexNodes[Math.floor(Math.random()*cortexNodes.length)];
    if(type==='thal2ctx'){
      // from thalamus to random cortex node — curved
      const cx=lerp(T.x,target.x,.55),cy=T.y-30;
      return bezier(T.x,T.y,cx,cy,target.x,target.y,p);
    }
    if(type==='ctx2thal'){
      const src=cortexNodes[Math.floor(Math.random()*cortexNodes.length)];
      const cx=lerp(src.x,T.x,.55),cy=T.y-30;
      return bezier(src.x,src.y,cx,cy,T.x,T.y,p);
    }
    if(type==='hippo2ctx'){
      const tgt=cortexNodes[Math.floor(Math.random()*cortexNodes.length)];
      const cx=lerp(H.x,tgt.x,.55),cy=H.y+40;
      return bezier(H.x,H.y,cx,cy,tgt.x,tgt.y,p);
    }
    if(type==='ctx2hippo'){
      const src=cortexNodes[Math.floor(Math.random()*cortexNodes.length)];
      const cx=lerp(src.x,H.x,.55),cy=H.y+40;
      return bezier(src.x,src.y,cx,cy,H.x,H.y,p);
    }
    if(type==='replay'){
      // hippo arcs looping around itself
      const a=p*Math.PI*2+p*2;
      return {x:H.x+Math.cos(a)*H.r*1.6, y:H.y+Math.sin(a)*H.r*1.1};
    }
  }
  function bezier(x0,y0,cx,cy,x1,y1,t){
    const u=1-t;
    return {
      x: u*u*x0 + 2*u*t*cx + t*t*x1,
      y: u*u*y0 + 2*u*t*cy + t*t*y1,
    };
  }

  // Mouse attractor
  let mx=-999,my=-999;
  addEventListener('mousemove',e=>{
    const r=c.getBoundingClientRect();
    mx=e.clientX-r.left;my=e.clientY-r.top;
  });

  function frame(){
    t+=1;
    ctx.clearRect(0,0,w,h);

    // Background glow for each hub
    const T=thal(),H=hippo();
    const g1=ctx.createRadialGradient(T.x,T.y,0,T.x,T.y,T.r*6);
    g1.addColorStop(0,`rgba(${TRC_THEME.thalamus},.18)`);g1.addColorStop(1,`rgba(${TRC_THEME.thalamus},0)`);
    ctx.fillStyle=g1;ctx.fillRect(0,0,w,h);
    const g2=ctx.createRadialGradient(H.x,H.y,0,H.x,H.y,H.r*6);
    g2.addColorStop(0,`rgba(${TRC_THEME.hippo},.14)`);g2.addColorStop(1,`rgba(${TRC_THEME.hippo},0)`);
    ctx.fillStyle=g2;ctx.fillRect(0,0,w,h);

    // CORTEX grid lines
    ctx.strokeStyle=`rgba(${TRC_THEME.cortex},.12)`;ctx.lineWidth=1;
    for(let i=0;i<cortexNodes.length;i++){
      const n=cortexNodes[i];
      // connect right
      if(n.col<cols-1){const r=cortexNodes[i+1];ctx.beginPath();ctx.moveTo(n.x,n.y);ctx.lineTo(r.x,r.y);ctx.stroke();}
      // connect down
      if(n.row<rows-1){const d=cortexNodes[i+cols];ctx.beginPath();ctx.moveTo(n.x,n.y);ctx.lineTo(d.x,d.y);ctx.stroke();}
    }

    // Cortex nodes
    cortexNodes.forEach((n,i)=>{
      const dx=mx-n.x,dy=my-n.y,d2=dx*dx+dy*dy;
      const boost=d2<40000?Math.max(0,1-Math.sqrt(d2)/200):0;
      const pulse=.5+.5*Math.sin(t*.04+n.phase);
      const a=n.base*.5+pulse*.3+boost*.6;
      const r=3+pulse*1.5+boost*4;
      ctx.fillStyle=`rgba(${TRC_THEME.cortex},${a})`;
      ctx.beginPath();ctx.arc(n.x,n.y,r,0,Math.PI*2);ctx.fill();
      if(boost>.2){
        ctx.strokeStyle=`rgba(${TRC_THEME.trc},${boost*.7})`;
        ctx.lineWidth=1;ctx.beginPath();ctx.arc(n.x,n.y,r+3+boost*4,0,Math.PI*2);ctx.stroke();
      }
    });

    // Thalamus ring (amber)
    for(let k=3;k>=0;k--){
      ctx.beginPath();ctx.arc(T.x,T.y,T.r+k*4,0,Math.PI*2);
      ctx.strokeStyle=`rgba(${TRC_THEME.thalamus},${.08+(3-k)*.06})`;ctx.lineWidth=1.5;ctx.stroke();
    }
    ctx.fillStyle=`rgba(${TRC_THEME.thalamus},.5)`;
    ctx.beginPath();ctx.arc(T.x,T.y,T.r*.35,0,Math.PI*2);ctx.fill();
    // label
    ctx.fillStyle=`rgba(${TRC_THEME.thalamus},.85)`;
    ctx.font='600 10px JetBrains Mono';ctx.textAlign='center';
    ctx.fillText('THALAMUS',T.x,T.y+T.r+18);

    // Hippocampus arc (violet)
    ctx.strokeStyle=`rgba(${TRC_THEME.hippo},.5)`;ctx.lineWidth=2;
    ctx.beginPath();ctx.arc(H.x,H.y,H.r,.2,Math.PI*2-.2);ctx.stroke();
    ctx.fillStyle=`rgba(${TRC_THEME.hippo},.45)`;
    ctx.beginPath();ctx.arc(H.x,H.y,H.r*.4,0,Math.PI*2);ctx.fill();
    ctx.fillStyle=`rgba(${TRC_THEME.hippo},.85)`;
    ctx.font='600 10px JetBrains Mono';ctx.fillText('HIPPOCAMPUS',H.x,H.y+H.r+18);

    // Label CORTEX
    ctx.fillStyle=`rgba(${TRC_THEME.cortex},.6)`;
    ctx.font='600 10px JetBrains Mono';ctx.textAlign='left';
    ctx.fillText('CORTICAL COLUMNS',cortexNodes[0].x,cortexNodes[0].y-18);

    // Advance pulses
    for(let i=pulses.length-1;i>=0;i--){
      const p=pulses[i];p.t+=p.speed;
      if(p.t>=1){pulses.splice(i,1);continue;}
      const pt=pathPoint(p.type,p.t);
      let col;
      if(p.type.startsWith('thal'))col=`rgba(${TRC_THEME.thalamus},`;
      else if(p.type.startsWith('hippo'))col=`rgba(${TRC_THEME.hippo},`;
      else if(p.type.startsWith('ctx2thal'))col=`rgba(${TRC_THEME.thalamus},`;
      else if(p.type.startsWith('ctx2hippo'))col=`rgba(${TRC_THEME.hippo},`;
      else col=`rgba(${TRC_THEME.replay},`;
      const a=Math.sin(p.t*Math.PI);
      ctx.fillStyle=col+(a*.9)+')';
      ctx.beginPath();ctx.arc(pt.x,pt.y,2.5,0,Math.PI*2);ctx.fill();
      ctx.fillStyle=col+(a*.25)+')';
      ctx.beginPath();ctx.arc(pt.x,pt.y,6,0,Math.PI*2);ctx.fill();
    }

    requestAnimationFrame(frame);
  }
  frame();
  addEventListener('resize',layoutCortex);
})();

