const STREAM = (() => {
  // Recorded step grid: 500..22000 by 500 (43 points per series)
  const STEP_MIN = 500, STEP_MAX = 22000, STEP_DT = 500;

  // Endpoints @ step 22k, derived directly from STREAM_DATA so they always
  // stay in sync with the underlying CSVs.
  const endpts = {};
  Object.entries(STREAM_DATA).forEach(([order, models]) => {
    endpts[order] = {};
    Object.entries(models).forEach(([m, series]) => {
      endpts[order][m] = series[series.length - 1][1];
    });
  });

  // Task ordering and the windows over which each task is the active
  // training distribution. Verified against the recorded eval-step ranges
  // for each ordering (a task starts producing eval points at the step
  // where its training window opens).
  const orderMap = {
    CGW:['C4','GSM8K','WikiText-103'],
    GCW:['GSM8K','C4','WikiText-103'],
    GWC:['GSM8K','WikiText-103','C4'],
    WCG:['WikiText-103','C4','GSM8K'],
    WGC:['WikiText-103','GSM8K','C4'],
  };
  const winFor = (order) => {
    if(order==='CGW')return [[0,10000],[10000,12000],[12000,22000]];
    if(order==='GCW')return [[0,2000],[2000,12000],[12000,22000]];
    if(order==='GWC')return [[0,2000],[2000,12000],[12000,22000]];
    if(order==='WCG')return [[0,10000],[10000,20000],[20000,22000]];
    if(order==='WGC')return [[0,10000],[10000,12000],[12000,22000]];
  };

  const modelColors = {
    Transformer:'#4c78a8',
    MoE:'#f58518',
    Mamba:'#54a24b',
    DeepSeek:'#eeca3b',
    BlkAttnRes:'#b279a2',
    FALCON:'#ff9da6',
    LoraDRS:'#9d9d9d',
    TRC2:'#ff3b3b',
  };

  // Linear-interpolate the recorded series at an arbitrary step.
  // Returns 0 below the first sample and clamps to the last sample above.
  function valueAt(order, model, step) {
    const series = STREAM_DATA[order] && STREAM_DATA[order][model];
    if (!series || series.length === 0) return 0;
    const first = series[0], last = series[series.length - 1];
    if (step <= first[0]) return Math.max(0, first[1] * (step / first[0]));
    if (step >= last[0])  return last[1];
    // Series is on a uniform 500-step grid starting at 500 → O(1) index lookup
    const idxF = (step - STEP_MIN) / STEP_DT;
    const i0 = Math.floor(idxF), i1 = Math.min(i0 + 1, series.length - 1);
    const t = idxF - i0;
    const [x0, y0] = series[i0], [x1, y1] = series[i1];
    if (x1 === x0) return y0;
    // Fall back to actual x interpolation in case of any irregularity
    const u = (step - x0) / (x1 - x0);
    return y0 + (y1 - y0) * u;
  }

  return { endpts, orderMap, winFor, modelColors, valueAt, STEP_MIN, STEP_MAX };
})();

(() => {
  const canv=document.getElementById('streamCanvas'),ctx=canv.getContext('2d');
  const bar=document.getElementById('streamBar'),ph=document.getElementById('playhead');
  const mStep=document.getElementById('mStep'),mTask=document.getElementById('mTask'),mTrc=document.getElementById('mTrc'),mBase=document.getElementById('mBase');
  const legendEl=document.getElementById('streamLegend');
  let w,h,dpr,order='CGW',step=11000,stepMax=22000;
  const enabled={};Object.keys(STREAM.modelColors).forEach(m=>enabled[m]=true);

  // Build legend
  Object.entries(STREAM.modelColors).forEach(([m,c])=>{
    const el=document.createElement('button');el.className='it chip';el.style.padding='6px 10px';
    el.innerHTML=`<span class="sw ${m==='TRC2'?'trc2':''}" style="display:inline-block;width:16px;height:3px;background:${c};margin-right:8px;vertical-align:middle;${m==='TRC2'?'box-shadow:0 0 8px '+c:''}"></span>${m==='TRC2'?'TRC² (ours)':m}`;
    el.addEventListener('click',()=>{enabled[m]=!enabled[m];el.style.opacity=enabled[m]?1:.35;draw();});
    legendEl.appendChild(el);
  });

  function resize(){
    dpr=Math.min(2,devicePixelRatio||1);
    w=canv.offsetWidth;h=canv.offsetHeight;
    canv.width=w*dpr;canv.height=h*dpr;
    ctx.setTransform(dpr,0,0,dpr,0,0);
    draw();
  }
  addEventListener('resize',resize);

  // Real recorded AUFC trajectories live in STREAM.valueAt — no precompute needed,
  // it's an O(1) table lookup with linear interp between 500-step grid samples.
  const curveAt = (m, s) => STREAM.valueAt(order, m, s);

  function draw(){
    ctx.clearRect(0,0,w,h);
    const PAD={l:56,r:22,t:18,b:42};
    const W=w-PAD.l-PAD.r,H=h-PAD.t-PAD.b;

    // Fill canvas bg first
    ctx.fillStyle = TRC_THEME.isDark ? '#0e0e1a' : '#faf8f3';
    ctx.fillRect(0,0,w,h);

    // Task-window background stripes
    const win=STREAM.winFor(order);
    const tasks=STREAM.orderMap[order];
    const taskColor=TRC_THEME.isDark
      ? {C4:'rgba(96,165,250,.18)','WikiText-103':'rgba(244,114,182,.15)',GSM8K:'rgba(52,211,153,.18)'}
      : {C4:'rgba(37,99,235,.12)','WikiText-103':'rgba(190,24,93,.10)',GSM8K:'rgba(4,120,87,.12)'};
    win.forEach((wi,i)=>{
      const x0=PAD.l+(wi[0]/stepMax)*W,x1=PAD.l+(wi[1]/stepMax)*W;
      ctx.fillStyle=taskColor[tasks[i]];
      ctx.fillRect(x0,PAD.t,x1-x0,H);
      // label
      ctx.fillStyle=TRC_THEME.axisFaint;
      ctx.font='600 10px JetBrains Mono';ctx.textAlign='center';
      ctx.fillText(tasks[i],(x0+x1)/2,PAD.t+14);
      // boundary dashed
      if(i<win.length-1){
        ctx.save();ctx.setLineDash([4,4]);
        ctx.strokeStyle=TRC_THEME.grid;ctx.lineWidth=1;
        ctx.beginPath();ctx.moveTo(x1,PAD.t);ctx.lineTo(x1,PAD.t+H);ctx.stroke();
        ctx.restore();
      }
    });

    // Y axis: 0 to 5 (AUFC)
    const yMax=5;
    ctx.strokeStyle=TRC_THEME.grid;ctx.lineWidth=1;
    for(let y=0;y<=5;y++){
      const yy=PAD.t+H-(y/yMax)*H;
      ctx.beginPath();ctx.moveTo(PAD.l,yy);ctx.lineTo(PAD.l+W,yy);ctx.stroke();
      ctx.fillStyle=TRC_THEME.axisFaint;ctx.font='10px JetBrains Mono';ctx.textAlign='right';
      ctx.fillText(y,PAD.l-6,yy+3);
    }
    ctx.fillStyle=TRC_THEME.axisInk;ctx.font='10px JetBrains Mono';ctx.textAlign='left';
    ctx.fillText('PPL AUFC',PAD.l,PAD.t-4);

    // X axis ticks
    [0,5000,10000,15000,20000].forEach(s=>{
      const x=PAD.l+(s/stepMax)*W;
      ctx.fillStyle=TRC_THEME.axisFaint;ctx.font='10px JetBrains Mono';ctx.textAlign='center';
      ctx.fillText((s/1000)+'k',x,PAD.t+H+16);
    });
    ctx.fillStyle=TRC_THEME.axisInk;ctx.font='10px JetBrains Mono';
    ctx.fillText('Optimizer step',PAD.l+W/2,PAD.t+H+32);

    // Draw curves
    const N=240;
    Object.entries(STREAM.modelColors).forEach(([m,col])=>{
      if(!enabled[m])return;
      ctx.strokeStyle=col;
      ctx.lineWidth=m==='TRC2'?3:1.8;
      ctx.globalAlpha=m==='TRC2'?1:1;
      if(m==='TRC2')ctx.shadowColor=col,ctx.shadowBlur=10; else ctx.shadowBlur=0;
      ctx.beginPath();
      for(let i=0;i<=N;i++){
        const s=(i/N)*stepMax;
        const v=curveAt(m,s);
        const x=PAD.l+(s/stepMax)*W;
        const y=PAD.t+H-Math.min(v,yMax)/yMax*H;
        i?ctx.lineTo(x,y):ctx.moveTo(x,y);
      }
      ctx.stroke();
      ctx.shadowBlur=0;ctx.globalAlpha=1;
    });

    // Playhead vertical line
    const px=PAD.l+(step/stepMax)*W;
    ctx.strokeStyle=`rgba(${TRC_THEME.trc},.9)`;ctx.lineWidth=1.5;
    ctx.beginPath();ctx.moveTo(px,PAD.t);ctx.lineTo(px,PAD.t+H);ctx.stroke();
    // value dots at step
    Object.entries(STREAM.modelColors).forEach(([m,col])=>{
      if(!enabled[m])return;
      const v=curveAt(m,step);
      const y=PAD.t+H-Math.min(v,yMax)/yMax*H;
      ctx.fillStyle=col;
      ctx.beginPath();ctx.arc(px,y,m==='TRC2'?5:3,0,Math.PI*2);ctx.fill();
      if(m==='TRC2'){
        ctx.strokeStyle=`rgba(${TRC_THEME.trc},.35)`;ctx.lineWidth=1;
        ctx.beginPath();ctx.arc(px,y,10,0,Math.PI*2);ctx.stroke();
      }
    });

    // Update metrics
    ph.style.left=((step/stepMax)*100)+'%';
    mStep.textContent=step.toLocaleString();
    // find task
    const wi2=STREAM.winFor(order);
    let taskNow=tasks[0];
    for(let i=0;i<wi2.length;i++)if(step>=wi2[i][0]&&step<=wi2[i][1])taskNow=tasks[i];
    mTask.textContent=taskNow;
    mTrc.textContent=curveAt('TRC2',step).toFixed(2);
    // best baseline = min among non-TRC2 enabled
    let best=Infinity,bestM='—';
    Object.keys(STREAM.modelColors).forEach(m=>{
      if(m==='TRC2'||!enabled[m])return;
      const v=curveAt(m,step);if(v<best){best=v;bestM=m;}
    });
    mBase.textContent=(isFinite(best)?best.toFixed(2):'—');
  }

  // Scrub interactions
  function setStepFromX(clientX){
    const r=bar.getBoundingClientRect();
    const k=Math.max(0,Math.min(1,(clientX-r.left)/r.width));
    step=Math.round(k*stepMax);draw();
  }
  let dragging=false;
  bar.addEventListener('mousedown',e=>{dragging=true;setStepFromX(e.clientX);});
  addEventListener('mousemove',e=>{if(dragging)setStepFromX(e.clientX);});
  addEventListener('mouseup',()=>dragging=false);
  // touch
  bar.addEventListener('touchstart',e=>{dragging=true;setStepFromX(e.touches[0].clientX);},{passive:true});
  addEventListener('touchmove',e=>{if(dragging)setStepFromX(e.touches[0].clientX);},{passive:true});
  addEventListener('touchend',()=>dragging=false);
  // click anywhere on canvas
  canv.addEventListener('click',e=>{
    const r=canv.getBoundingClientRect();
    const PAD={l:56,r:22};const W=r.width-PAD.l-PAD.r;
    const k=Math.max(0,Math.min(1,(e.clientX-r.left-PAD.l)/W));
    step=Math.round(k*stepMax);draw();
  });

  // Order buttons
  document.getElementById('streamOrderBtns').addEventListener('click',e=>{
    const b=e.target.closest('.chip');if(!b)return;
    document.querySelectorAll('#streamOrderBtns .chip').forEach(x=>x.classList.remove('active'));
    b.classList.add('active');order=b.dataset.order;draw();
  });

  // Auto-play: gentle drift
  let auto=true;
  canv.addEventListener('click',()=>auto=false);
  bar.addEventListener('mousedown',()=>auto=false);
  setInterval(()=>{if(auto){step+=120;if(step>stepMax)step=0;draw();}},60);

  addEventListener('themechange',()=>{draw();});
  resize();
})();

/* ══════════════════════════════════════════════════════════════
   ARCHITECTURE — FULL ANIMATED CANVAS (matches reference)
   ══════════════════════════════════════════════════════════════ */
(() => {
  const cvs = document.getElementById('archCanvas');
  if (!cvs) return;
  const c = cvs.getContext('2d');
  let W, H, dpr, showLabels = true, speedMult = 1, time = 0;

  // ── theme-aware colour palette ──
  function COL() {
    const dk = TRC_THEME.isDark;
    return {
      cortexFill:   dk?'rgba(147,197,253,0.12)':'rgba(37,99,235,0.09)',
      cortexStroke: dk?'rgba(96,165,250,0.50)':'rgba(37,99,235,0.60)',
      cortexText:   dk?'rgba(219,234,254,0.96)':'rgba(30,64,175,0.95)',
      cortexSub:    dk?'rgba(191,219,254,0.74)':'rgba(59,130,246,0.80)',
      lateFill:     dk?'rgba(125,211,252,0.10)':'rgba(14,165,233,0.07)',
      lateStroke:   dk?'rgba(56,189,248,0.40)':'rgba(14,165,233,0.55)',
      lateText:     dk?'rgba(224,242,254,0.92)':'rgba(7,89,133,0.92)',
      lateSub:      dk?'rgba(186,230,253,0.66)':'rgba(14,165,233,0.75)',
      thalFill:     dk?'rgba(253,224,71,0.12)':'rgba(180,83,9,0.08)',
      thalStroke:   dk?'rgba(251,191,36,0.50)':'rgba(180,83,9,0.70)',
      thalText:     dk?'rgba(254,240,138,0.96)':'rgba(120,53,15,0.95)',
      thalSub:      dk?'rgba(254,240,138,0.72)':'rgba(180,83,9,0.80)',
      hippoFill:    dk?'rgba(196,181,253,0.12)':'rgba(124,58,237,0.08)',
      hippoStroke:  dk?'rgba(167,139,250,0.45)':'rgba(124,58,237,0.60)',
      hippoText:    dk?'rgba(237,233,254,0.96)':'rgba(76,29,149,0.95)',
      hippoSub:     dk?'rgba(221,214,254,0.72)':'rgba(124,58,237,0.80)',
      gateFill:     dk?'rgba(251,207,232,0.12)':'rgba(190,24,93,0.07)',
      gateStroke:   dk?'rgba(244,114,182,0.45)':'rgba(190,24,93,0.65)',
      gateText:     dk?'rgba(252,231,243,0.96)':'rgba(131,24,67,0.95)',
      gateSub:      dk?'rgba(252,231,243,0.72)':'rgba(190,24,93,0.80)',
      replayFill:   dk?'rgba(187,247,208,0.10)':'rgba(4,120,87,0.07)',
      replayStroke: dk?'rgba(52,211,153,0.40)':'rgba(4,120,87,0.65)',
      replayText:   dk?'rgba(220,252,231,0.94)':'rgba(6,78,59,0.95)',
      replaySub:    dk?'rgba(220,252,231,0.70)':'rgba(4,120,87,0.80)',
      neutralFill:  dk?'rgba(255,255,255,0.05)':'rgba(0,0,0,0.04)',
      neutralStroke:dk?'rgba(203,213,225,0.30)':'rgba(100,116,139,0.40)',
      neutralText:  dk?'rgba(226,232,240,0.80)':'rgba(30,41,59,0.80)',
      neutralSub:   dk?'rgba(226,232,240,0.54)':'rgba(71,85,105,0.65)',
      flowMain:     dk?'rgba(147,197,253,A)':'rgba(37,99,235,A)',
      flowThal:     dk?'rgba(251,191,36,A)':'rgba(180,83,9,A)',
      flowHippo:    dk?'rgba(196,181,253,A)':'rgba(124,58,237,A)',
      flowGate:     dk?'rgba(244,114,182,A)':'rgba(190,24,93,A)',
      flowReplay:   dk?'rgba(74,222,128,A)':'rgba(4,120,87,A)',
      flowResidual: dk?'rgba(203,213,225,A)':'rgba(100,116,139,A)',
      bg:           dk?'#0b0b18':'#f5f2ec',
      mergeCircle:  dk?'rgba(255,255,255,0.22)':'rgba(0,0,0,0.25)',
      mergeFill:    dk?'rgba(255,255,255,0.05)':'rgba(255,255,255,0.70)',
      mergeTxt:     dk?'rgba(255,255,255,0.72)':'rgba(0,0,0,0.80)',
      mergeLbl:     dk?'rgba(255,255,255,0.44)':'rgba(0,0,0,0.55)',
      spine:        dk?'rgba(226,232,240,0.18)':'rgba(30,41,59,0.22)',
      spineFaint:   dk?'rgba(226,232,240,0.10)':'rgba(30,41,59,0.12)',
    };
  }

  const LABEL_SCALE = 1.0;
  const BOX_SCALE   = 1.0;

  function resize() {
    dpr = Math.min(2, devicePixelRatio || 1);
    // The canvas's direct parent (.arch-viz-inner) is the visible box.
    // Its grandparent (.arch-sticky) is a 2-column grid — using its width
    // would double the canvas's logical width and push content off-screen.
    const inner = cvs.parentElement; // .arch-viz-inner — the visible box
    W = (inner ? inner.clientWidth : 0) || 500;
    // Diagram is taller than wide; clamp to a sensible minimum so it stays legible
    // in narrow grid columns without making the sticky panel absurdly tall.
    H = Math.max(720, Math.min(W * 1.65, 920));
    cvs.width  = W * dpr;
    cvs.height = H * dpr;
    cvs.style.width  = W + 'px';
    cvs.style.height = H + 'px';
    c.setTransform(dpr, 0, 0, dpr, 0, 0);
    buildParticles();
  }
  addEventListener('themechange', () => { /* colours read live */ });

  // ── primitives ──
  function rr(x, y, w, h, r) {
    c.beginPath();
    c.moveTo(x+r, y);
    c.lineTo(x+w-r, y);
    c.quadraticCurveTo(x+w, y, x+w, y+r);
    c.lineTo(x+w, y+h-r);
    c.quadraticCurveTo(x+w, y+h, x+w-r, y+h);
    c.lineTo(x+r, y+h);
    c.quadraticCurveTo(x, y+h, x, y+h-r);
    c.lineTo(x, y+r);
    c.quadraticCurveTo(x, y, x+r, y);
  }
  function box(x, y, w, h, fc, sc, txt, tc, fs) {
    rr(x, y, w, h, 5);
    c.fillStyle = fc; c.fill();
    c.strokeStyle = sc; c.lineWidth = 1; c.stroke();
    if (txt && showLabels) {
      c.fillStyle = tc || sc;
      c.font = ((fs||7)*BOX_SCALE) + 'px "JetBrains Mono",monospace';
      c.textAlign = 'center'; c.textBaseline = 'middle';
      c.fillText(txt, x+w/2, y+h/2);
      c.textBaseline = 'alphabetic';
    }
  }
  function ln(x1, y1, x2, y2, col, lw, dash) {
    if (dash) c.setLineDash(dash);
    c.beginPath(); c.moveTo(x1,y1); c.lineTo(x2,y2);
    c.strokeStyle = col; c.lineWidth = lw||.8; c.stroke();
    if (dash) c.setLineDash([]);
  }
  function pln(pts, col, lw, dash) {
    if (dash) c.setLineDash(dash);
    c.beginPath(); c.moveTo(pts[0][0], pts[0][1]);
    for (let i=1;i<pts.length;i++) c.lineTo(pts[i][0], pts[i][1]);
    c.strokeStyle = col; c.lineWidth = lw||.8; c.stroke();
    if (dash) c.setLineDash([]);
  }
  function lbl(x, y, t, col, al, fs) {
    if (!showLabels) return;
    c.fillStyle = col;
    c.font = ((fs||7)*LABEL_SCALE) + 'px "JetBrains Mono",monospace';
    c.textAlign = al||'center';
    c.fillText(t, x, y);
  }
  function tip(x, y, d, s, col) {
    c.beginPath();
    if (d==='d') { c.moveTo(x-s,y-s); c.lineTo(x,y); c.lineTo(x+s,y-s); }
    else if (d==='r') { c.moveTo(x-s,y-s); c.lineTo(x,y); c.lineTo(x-s,y+s); }
    else if (d==='l') { c.moveTo(x+s,y-s); c.lineTo(x,y); c.lineTo(x+s,y+s); }
    else { c.moveTo(x-s,y+s); c.lineTo(x,y); c.lineTo(x+s,y+s); }
    c.strokeStyle = col; c.lineWidth = 1.3; c.stroke();
  }

  // ── layout ──
  function L() {
    const mx=W*.42, bw=Math.min(W*.30,200), bx=mx-bw/2, br=bx+bw;
    const thX=br+W*.025, thW=Math.min(W*.19,126);
    const hpX=mx+W*.09, hpW=Math.min(W*.32,212);
    const gtW=Math.min(W*.13,86), gtX=bx-W*.025-gtW;
    const bh=16, bs=13;
    const mergeX=br+W*.052, mergeY=H*.760;
    return {
      mx,bx,bw,br,thX,thW,hpX,hpW,gtX,gtW,bh,bs,mergeX,mergeY,
      inpY:H*.030,
      ecT:H*.072, ecB:H*.415,
      n1:H*.098, at:H*.142, r1:H*.212, n2:H*.242, mo:H*.282, r2:H*.336, l5:H*.370, rptY:H*.395,
      thT:H*.092, thB:H*.405,
      spY:H*.455,
      hpT:H*.435, hpB:H*.695,
      gtY:H*.600,
      lcT:H*.735, lcB:H*.845,
      nrmY:H*.878, outY:H*.918
    };
  }

  // ── waypoint particle ──
  class WP {
    constructor(wp, col, spd, sz) {
      this.wp=wp; this.col=col; this.spd=spd; this.sz=sz||1.5;
      this.t=Math.random(); this.segs=[]; this.total=0;
      for (let i=1;i<wp.length;i++) {
        const dx=wp[i][0]-wp[i-1][0], dy=wp[i][1]-wp[i-1][1];
        const d=Math.sqrt(dx*dx+dy*dy);
        this.segs.push(d); this.total+=d;
      }
    }
    pos() {
      let d=this.t*this.total;
      for (let i=0;i<this.segs.length;i++) {
        if (d<=this.segs[i]) {
          const f=d/this.segs[i];
          return {x:this.wp[i][0]+(this.wp[i+1][0]-this.wp[i][0])*f,
                  y:this.wp[i][1]+(this.wp[i+1][1]-this.wp[i][1])*f};
        }
        d-=this.segs[i];
      }
      return {x:this.wp[this.wp.length-1][0],y:this.wp[this.wp.length-1][1]};
    }
    update(){this.t=(this.t+this.spd*speedMult*.003)%1;}
    draw() {
      const col=this.col;
      const p=this.pos(), a=.26+Math.sin(this.t*Math.PI)*.34;
      c.beginPath(); c.arc(p.x,p.y,this.sz,0,Math.PI*2);
      c.fillStyle=col.replace('A)',a+')'); c.fill();
      c.beginPath(); c.arc(p.x,p.y,this.sz*3.5,0,Math.PI*2);
      c.fillStyle=col.replace('A)',(a*.12)+')'); c.fill();
    }
  }

  let particles=[];
  function buildParticles() {
    particles=[]; const l=L(); const col=COL();
    const cOutY  = l.l5+l.bs/2;
    const thInY  = l.thT+(l.thB-l.thT)*.22;
    const cToThX = l.br+18;
    const thLpX  = l.br+24;

    // 1a main spine early
    for(let i=0;i<10;i++) particles.push(new WP([
      [l.mx,l.inpY+l.bh],[l.mx,l.n1],[l.mx,l.at],[l.mx,l.r1],
      [l.mx,l.n2],[l.mx,l.mo],[l.mx,l.r2],[l.mx,l.l5],[l.mx,l.spY],[l.mx,l.lcT]
    ],col.flowMain,.56+Math.random()*.24,1.25+Math.random()));
    // 1b inside late stack
    for(let i=0;i<8;i++) particles.push(new WP([[l.mx,l.lcT],[l.mx,l.lcB]],col.flowMain,.42+Math.random()*.16,1.2+Math.random()*.8));
    // 1c exit
    for(let i=0;i<8;i++) particles.push(new WP([[l.mx,l.lcB],[l.mx,l.nrmY],[l.mx,l.outY]],col.flowMain,.24+Math.random()*.10,1.2+Math.random()*.8));
    // 2 thalamocortical loop
    for(let i=0;i<8;i++) particles.push(new WP([
      [l.br,cOutY],[cToThX,cOutY],[cToThX,thInY],[l.thX,thInY],
      [l.thX+l.thW/2,l.thT+(l.thB-l.thT)*.30],[l.thX+l.thW/2,l.thB-10],
      [l.thX+l.thW/2,l.thB+10],[thLpX,l.thB+10],[thLpX,l.at+l.bh],[l.br+2,l.at+l.bh]
    ],col.flowThal,.42+Math.random()*.22,1.1+Math.random()*.7));
    // 3 carried thalamic signal
    for(let i=0;i<5;i++) particles.push(new WP([
      [l.thX+l.thW/2,l.thB-8],[l.thX+l.thW/2,l.thB+8],[l.mergeX,l.thB+8],[l.mergeX,l.mergeY]
    ],col.flowThal,.26+Math.random()*.14,1+Math.random()*.45));
    // 4 merged side-input into late
    for(let i=0;i<5;i++) particles.push(new WP([
      [l.mergeX,l.mergeY],[l.br+2,l.mergeY],[l.br+2,l.lcT+18]
    ],col.flowThal,.28+Math.random()*.14,1+Math.random()*.5));
    // 5 H^linj -> hippo
    for(let i=0;i<6;i++) particles.push(new WP([
      [l.mx+4,l.spY],[l.hpX,l.spY],[l.hpX+18,l.hpT+28],[l.hpX+42,l.hpT+28]
    ],col.flowHippo,.36+Math.random()*.18,1.1+Math.random()*.5));
    // 6 mem_readout -> gate
    for(let i=0;i<5;i++) particles.push(new WP([
      [l.hpX+8,l.gtY],[l.mx+10,l.gtY],[l.gtX+l.gtW,l.gtY]
    ],col.flowHippo,.34+Math.random()*.16,1.1+Math.random()*.5));
    // 7 sg(H) -> gate
    for(let i=0;i<4;i++) particles.push(new WP([
      [l.mx,l.spY+2],[l.mx,l.gtY-10],[l.gtX+l.gtW,l.gtY-10]
    ],col.flowResidual,.28+Math.random()*.14,.95));
    // 8 F_hip -> merge
    for(let i=0;i<6;i++) particles.push(new WP([
      [l.gtX+l.gtW/2,l.gtY+28],[l.gtX+l.gtW/2,l.mergeY],[l.mergeX-7,l.mergeY]
    ],col.flowGate,.30+Math.random()*.16,1.05+Math.random()*.45));
    // 9 replay
    for(let i=0;i<4;i++) particles.push(new WP([
      [l.hpX+l.hpW,l.hpT+96],[l.hpX+l.hpW+16,l.hpT+96],[l.hpX+l.hpW+16,l.inpY+l.bh/2],[l.br,l.inpY+l.bh/2]
    ],col.flowReplay,.22+Math.random()*.12,.95+Math.random()*.45));
  }

  let drawStarted = false;
  function draw() {
    time += .016*speedMult;
    const col=COL(); const l=L();
    c.clearRect(0,0,W,H);

    // BG fill
    c.fillStyle=col.bg; c.fillRect(0,0,W,H);

    // Clip to canvas bounds with small padding
    c.save();
    c.beginPath();
    c.rect(2, 2, W-4, H-4);
    c.clip();
    box(l.bx,l.inpY,l.bw,l.bh,col.thalFill,col.thalStroke,'H⁽⁰⁾ = Dropout(E[x₁:T])',col.thalText,8);
    lbl(l.mx,l.inpY+l.bh+10,'E ∈ ℝⱽˣᵈ · no pos emb · weight-tied',col.thalSub,'center',5.5);
    ln(l.mx,l.inpY+l.bh,l.mx,l.ecT,col.spine);
    tip(l.mx,l.ecT,'d',3,col.spine);

    // EARLY CORTEX box
    rr(l.bx-8,l.ecT,l.bw+16,l.ecB-l.ecT,8);
    c.fillStyle=col.cortexFill; c.fill();
    c.strokeStyle=col.cortexStroke; c.lineWidth=1.4; c.stroke();
    lbl(l.bx-2,l.ecT+11,'EARLY CORTICAL STACK',col.cortexText,'left',7.5);
    lbl(l.br+8,l.ecT+11,'ℓ = 1…ℓᵢₙⱼ',col.cortexSub,'right',6.5);

    box(l.bx+10,l.n1,l.bw-20,l.bs,col.neutralFill,col.neutralStroke,'U = RMSNorm(H⁽ℓ⁻¹⁾)',col.neutralText,7);
    ln(l.mx,l.n1+l.bs,l.mx,l.at,col.spineFaint);
    box(l.bx+10,l.at,l.bw-20,l.bh*2,col.cortexFill,col.cortexStroke,'GQA Self-Attention + RoPE',col.cortexText,7.5);
    lbl(l.mx,l.at+l.bh*2+8,'col 1: no thal input · later cols: Q-mod via Z',col.cortexSub,'center',5.2);
    ln(l.mx,l.at+l.bh*2,l.mx,l.r1,col.spineFaint);
    tip(l.mx,l.r1,'d',2.5,col.spine);
    box(l.bx+10,l.r1,l.bw-20,l.bs,col.neutralFill,col.neutralStroke,'H̃ = H⁽ℓ⁻¹⁾ + Dropout(A)',col.neutralText,6.5);
    ln(l.mx,l.r1+l.bs,l.mx,l.n2,col.spineFaint);
    box(l.bx+10,l.n2,l.bw-20,l.bs,col.neutralFill,col.neutralStroke,'V_moe = RMSNorm(H̃)',col.neutralText,7);
    ln(l.mx,l.n2+l.bs,l.mx,l.mo,col.spineFaint);
    box(l.bx+10,l.mo,l.bw-20,l.bh*1.5,col.hippoFill,col.hippoStroke,'MoE SwiGLU · E=8 k=2+shared',col.hippoText,7);
    ln(l.mx,l.mo+l.bh*1.5,l.mx,l.r2,col.spineFaint);
    tip(l.mx,l.r2,'d',2.5,col.spine);
    box(l.bx+10,l.r2,l.bw-20,l.bs,col.neutralFill,col.neutralStroke,'H⁽ℓ⁾ = H̃ + Dropout(M)',col.neutralText,6.5);
    ln(l.mx,l.r2+l.bs,l.mx,l.l5,col.spineFaint);
    box(l.bx+10,l.l5,l.bw-20,l.bs,col.cortexFill,col.cortexStroke,'C⁽ℓ⁾ = W_L5 · H⁽ℓ⁾',col.cortexSub,7);
    lbl(l.mx,l.rptY,'repeat for ℓ = 1…ℓᵢₙⱼ',col.cortexSub,'center',6);

    // residual brackets
    pln([[l.bx,l.n1+l.bs/2],[l.bx-8,l.n1+l.bs/2],[l.bx-8,l.r1+l.bs/2],[l.bx,l.r1+l.bs/2]],col.neutralStroke,.7,[3,3]);
    tip(l.bx,l.r1+l.bs/2,'r',2,col.neutralStroke);
    pln([[l.bx,l.r1+l.bs/2],[l.bx-14,l.r1+l.bs/2],[l.bx-14,l.r2+l.bs/2],[l.bx,l.r2+l.bs/2]],col.neutralStroke,.7,[3,3]);
    tip(l.bx,l.r2+l.bs/2,'r',2,col.neutralStroke);

    // THALAMIC ROUTER box
    rr(l.thX,l.thT,l.thW,l.thB-l.thT,7);
    c.fillStyle=col.thalFill; c.fill();
    c.strokeStyle=col.thalStroke; c.lineWidth=1.2; c.stroke();
    lbl(l.thX+l.thW/2,l.thT+12,'THALAMIC ROUTER',col.thalText,'center',7.5);
    const thIY=l.thT+26;
    lbl(l.thX+l.thW/2,thIY,   'Causal inter-column feedback',col.thalSub,'center',5.8);
    lbl(l.thX+l.thW/2,thIY+13,'compress → local + diffuse paths',col.thalSub,'center',5.2);
    lbl(l.thX+l.thW/2,thIY+24,'focal+diffuse → TRN competition',col.thalSub,'center',5.0);
    box(l.thX+8,thIY+36,l.thW-16,l.bh,col.thalFill,col.thalStroke,'TRN (groupwise divisive)',col.thalText,5.8);
    lbl(l.thX+l.thW/2,l.thB-12,'Z → NEXT column q',col.thalSub,'center',5.8);

    // C^(ℓ) -> thalamus
    const cOutY=l.l5+l.bs/2, thInY=l.thT+(l.thB-l.thT)*.22, cToThX=l.br+18;
    pln([[l.br,cOutY],[cToThX,cOutY],[cToThX,thInY],[l.thX,thInY]],col.thalStroke,1.1);
    tip(l.thX,thInY,'r',2.5,col.thalStroke);
    lbl(l.br+4,l.l5+4,'C⁽ℓ⁾',col.thalText,'left',6);

    // thalamus return loop to early Q
    const thLpX=l.br+24;
    pln([[l.thX+l.thW/2,l.thB],[l.thX+l.thW/2,l.thB+10],[thLpX,l.thB+10],[thLpX,l.at+l.bh],[l.br+2,l.at+l.bh]],col.thalStroke,1.0,[5,3]);
    tip(l.br+2,l.at+l.bh,'l',2.5,col.thalStroke);
    lbl(l.thX+l.thW*.46,(l.thB+l.at)/2+10,'Z⁽ℓ⁾ → col ℓ+1',col.thalSub,'center',5.3);

    // carried thalamic signal into merge
    pln([[l.thX+l.thW/2,l.thB],[l.thX+l.thW/2,l.thB+8],[l.mergeX,l.thB+8],[l.mergeX,l.mergeY-7]],col.thalStroke,1.0,[6,4]);
    tip(l.mergeX,l.mergeY-7,'d',2.5,col.thalStroke);
    lbl(l.mergeX+8,(l.thB+l.mergeY)/2-8,'thalamic → late stack',col.thalSub,'left',5.1);

    // SPLIT node
    ln(l.mx,l.ecB,l.mx,l.spY,col.spine,1);
    c.beginPath(); c.arc(l.mx,l.spY,5,0,Math.PI*2);
    c.fillStyle=col.cortexFill; c.fill();
    c.strokeStyle=col.cortexStroke; c.lineWidth=1; c.stroke();
    lbl(l.mx-26,l.spY-8,'H⁽ℓᵢₙⱼ⁾',col.cortexText,'right',7.5);

    // H^(ℓinj) -> hippocampus
    ln(l.mx+5,l.spY,l.hpX,l.spY,col.hippoStroke,1.2);
    tip(l.hpX,l.spY,'r',3,col.hippoStroke);
    lbl((l.mx+l.hpX)/2,l.spY-8,'H⁽ˡⁱⁿʲ⁾ → hippocampus',col.hippoSub,'center',5.4);

    // HIPPOCAMPAL MEMORY box
    rr(l.hpX,l.hpT,l.hpW,l.hpB-l.hpT,8);
    c.fillStyle=col.hippoFill; c.fill();
    c.strokeStyle=col.hippoStroke; c.lineWidth=1.4; c.stroke();
    lbl(l.hpX+l.hpW/2,l.hpT+12,'HIPPOCAMPAL MEMORY',col.hippoText,'center',7.5);
    const hw=(l.hpW-24)/2;
    box(l.hpX+8,l.hpT+22,hw,l.bh+4,col.hippoFill,col.hippoStroke,'read(x): top-k KV',col.hippoText,5.7);
    box(l.hpX+16+hw,l.hpT+22,hw,l.bh+4,col.hippoFill,col.hippoStroke,'TD critic fast/slow',col.hippoText,5.3);
    box(l.hpX+8,l.hpT+48,l.hpW-16,l.bs+2,col.hippoFill,col.hippoStroke,'fwd stash → flush after bwd',col.hippoSub,5.2);
    // replay sub-box
    const rpBx=l.hpX+8, rpBy=l.hpT+72, rpBw=l.hpW-16, rpBh=l.bh*3.0;
    box(rpBx,rpBy,rpBw,rpBh,col.replayFill,col.replayStroke,'',col.replayText,6.5);
    lbl(l.hpX+l.hpW/2,rpBy+18,'Replay: past chunks only',col.replayText,'center',6.0);
    lbl(l.hpX+l.hpW/2,rpBy+31,'recent ring + long-term reservoir',col.replaySub,'center',4.8);
    lbl(l.hpX+l.hpW/2,rpBy+43,'replay_ids → emb → columns → head',col.replaySub,'center',4.5);
    // pulsing mem-slot dots
    for(let i=0;i<10;i++){
      const sx=l.hpX+16+i*((l.hpW-32)/9), sy=l.hpB-22;
      const a=0.16+Math.sin(time*3.2+i*1.0)*.14;
      const r=3.8+Math.sin(time*3.2+i*1.0)*1.1;
      c.beginPath(); c.arc(sx,sy,r,0,Math.PI*2);
      c.fillStyle=col.hippoStroke.replace('0.60',Math.max(.05,a).toFixed(2)).replace('0.45',Math.max(.05,a).toFixed(2)); c.fill();
    }
    lbl(l.hpX+l.hpW/2,l.hpB-8,'mem_keys · mem_vals · N_slots = 512',col.hippoSub,'center',5);

    // mem_readout -> gate
    pln([[l.hpX+8,l.gtY],[l.mx+10,l.gtY],[l.gtX+l.gtW,l.gtY]],col.hippoStroke,1.0,[4,3]);
    tip(l.gtX+l.gtW,l.gtY,'l',2.5,col.hippoStroke);
    lbl(l.mx+28,l.gtY-6,'mem_readout M',col.hippoText,'left',6);

    // FEEDBACK GATE
    rr(l.gtX,l.gtY-l.bh,l.gtW,l.bh*2.8,5);
    c.fillStyle=col.gateFill; c.fill();
    c.strokeStyle=col.gateStroke; c.lineWidth=1; c.stroke();
    lbl(l.gtX+l.gtW/2,l.gtY-4,'HIPPO GATE',col.gateText,'center',6.2);
    lbl(l.gtX+l.gtW/2,l.gtY+9, 'G=σ(W_g[sg(H),M]+b)',col.gateSub,'center',5.1);
    lbl(l.gtX+l.gtW/2,l.gtY+20,'F_hip=σ(a)·W(G⊙M)',col.gateSub,'center',4.8);

    // sg(H) -> gate
    pln([[l.mx,l.spY+2],[l.mx,l.gtY-10],[l.gtX+l.gtW,l.gtY-10]],col.neutralStroke,.9,[3,3]);
    tip(l.gtX+l.gtW,l.gtY-10,'l',2.5,col.neutralStroke);
    lbl(l.mx-6,l.gtY-14,'sg(H⁽ˡⁱⁿʲ⁾)',col.neutralSub,'right',5.2);

    // MERGE NODE Σ
    c.beginPath(); c.arc(l.mergeX,l.mergeY,7,0,Math.PI*2);
    c.fillStyle=col.mergeFill; c.fill();
    c.strokeStyle=col.mergeCircle; c.lineWidth=1; c.stroke();
    lbl(l.mergeX,l.mergeY+2,'Σ',col.mergeTxt,'center',7);
    lbl(l.mergeX+6,l.mergeY-12,'th_in = thal + hippo_feedback',col.mergeLbl,'left',5.0);
    lbl(l.mergeX+6,l.mergeY-2,'late cols: Q-mod = merged side-input',col.mergeLbl,'left',4.6);

    // gate -> merge
    pln([[l.gtX+l.gtW/2,l.gtY+28],[l.gtX+l.gtW/2,l.mergeY],[l.mergeX-7,l.mergeY]],col.gateStroke,1.0,[4,3]);
    tip(l.mergeX-7,l.mergeY,'r',2.5,col.gateStroke);
    lbl(l.gtX+l.gtW/2+8,l.mergeY-6,'F_hip',col.gateText,'left',6);

    // main x stream continues separately
    ln(l.mx,l.spY,l.mx,l.lcT,col.spineFaint);

    // LATE CORTEX box
    rr(l.bx-8,l.lcT,l.bw+16,l.lcB-l.lcT,8);
    c.fillStyle=col.lateFill; c.fill();
    c.strokeStyle=col.lateStroke; c.lineWidth=1.3; c.stroke();
    lbl(l.bx-2,l.lcT+12,'LATE CORTICAL STACK',col.lateText,'left',7.5);
    lbl(l.br+8,l.lcT+12,'ℓ = ℓᵢₙⱼ+1…L',col.lateSub,'right',6.5);
    lbl(l.mx,l.lcT+28,'hidden state x: down center',col.lateSub,'center',5.2);
    lbl(l.mx,l.lcT+40,'late attn Q-mod: merged side-input',col.lateSub,'center',5.0);
    lbl(l.mx,l.lcT+52,'late cols keep own thalamic loop',col.thalSub,'center',4.8);

    // merge → late stack entry
    pln([[l.mergeX+7,l.mergeY],[l.br+2,l.mergeY],[l.br+2,l.lcT+18]],col.thalStroke,1.0,[5,3]);
    tip(l.br+2,l.lcT+18,'u',2.5,col.thalStroke);

    // thalamic rail inside late cortex
    pln([[l.br+14,l.lcT+18],[l.br+24,l.lcT+18],[l.br+24,l.lcB-8],[l.br+14,l.lcB-8]],col.thalStroke,.9,[4,3]);
    lbl(l.br+28,(l.lcT+l.lcB)/2,'Z updates: late cols',col.thalSub,'left',4.8);

    ln(l.mx,l.lcB,l.mx,l.nrmY,col.spineFaint);
    tip(l.mx,l.nrmY,'d',2.5,col.spine);

    // OUTPUT
    box(l.bx+10,l.nrmY,l.bw-20,l.bs,col.neutralFill,col.neutralStroke,'RMSNorm(H⁽ᴸ⁾)',col.neutralText,7);
    ln(l.mx,l.nrmY+l.bs,l.mx,l.outY,col.spineFaint);
    tip(l.mx,l.outY,'d',3,col.spine);
    box(l.bx,l.outY,l.bw,l.bh+2,col.thalFill,col.thalStroke,'logits = RMSNorm(Hᴸ) · W_vocabᵀ',col.thalText,7.5);
    lbl(l.mx,l.outY+l.bh+14,'W_vocab = E (tied)',col.thalSub,'center',5.5);

    // REPLAY LOOP
    const rpX=l.hpX+l.hpW+16;
    pln([[l.hpX+l.hpW,l.hpT+96],[rpX,l.hpT+96],[rpX,l.inpY+l.bh/2],[l.br,l.inpY+l.bh/2]],col.replayStroke,1.0,[5,3]);
    tip(l.br,l.inpY+l.bh/2,'l',2.5,col.replayStroke);
    c.save();
    c.translate(rpX+10,(l.hpT+l.inpY)/2+34);
    c.rotate(-Math.PI/2);
    lbl(0,0,'replay: tok_emb → cols → lm_head',col.replaySub,'center',5.0);
    c.restore();

    // particles
    particles.forEach(p => { p.update(); p.draw(); });

    c.restore(); // end clip
    requestAnimationFrame(draw);
  }

  // Defer until layout is fully settled — retry until width > 0
  function initWhenReady(attempts) {
    const parent = cvs.parentElement; // arch-viz-inner
    const vizOuter = parent ? parent.parentElement : null; // arch-viz
    const w = (vizOuter ? vizOuter.offsetWidth : 0) || (parent ? parent.offsetWidth : 0);
    if (w > 10) {
      resize();
      if (!drawStarted) { drawStarted = true; draw(); }
    } else if (attempts > 0) {
      setTimeout(() => initWhenReady(attempts - 1), 50);
    }
  }
  initWhenReady(20);
  addEventListener('resize', () => { resize(); buildParticles(); });

  window.archToggleSpeed = function() {
    speedMult = speedMult===1?2:speedMult===2?.5:1;
    const b = document.getElementById('archBtnSpeed');
    if(b) b.textContent = speedMult+'× Speed';
  };
  window.archToggleLabels = function() {
    showLabels = !showLabels;
    const b = document.getElementById('archBtnLabels');
    if(b) b.classList.toggle('active', showLabels);
  };

  // Observe steps
  const steps = document.querySelectorAll('.arch-step');
  const io2 = new IntersectionObserver(es => {
    es.forEach(e => {
      if (e.isIntersecting && e.intersectionRatio > .45) {
        steps.forEach(s => s.classList.remove('active'));
        e.target.classList.add('active');
      }
    });
  }, {threshold:[.45,.75], rootMargin:'-20% 0px -30% 0px'});
  steps.forEach(s => io2.observe(s));
})();

/* ══════════════════════════════════════════════════════════════
   RADAR CHART (native SVG)
   ══════════════════════════════════════════════════════════════ */
(() => {
  // Axes: C4 PPL⁻¹, Wiki PPL⁻¹, GSM PPL⁻¹, GSM Acc, Wiki BLEU, C4 BLEU
  // Values come from Table 2 best-config-per-architecture.
  const axes=['C4 PPL⁻¹','Wiki PPL⁻¹','GSM PPL⁻¹','GSM8K Acc','Wiki BLEU','C4 BLEU'];
  // Normalized 0..1 values (outer=better). Approximated from paper's Fig 5.
  const models={
    Transformer:{c:'#4c78a8',v:[.55,.55,.45,.55,.58,.62]},
    MoE:        {c:'#f58518',v:[.40,.35,.35,.45,.50,.32]},
    Mamba:      {c:'#54a24b',v:[.35,.32,.20,.30,.48,.35]},
    DeepSeek:   {c:'#eeca3b',v:[.60,.55,.40,.60,.55,.68]},
    BlkAttnRes: {c:'#b279a2',v:[.55,.58,.35,.70,.62,.55]},
    FALCON:     {c:'#ff9da6',v:[.65,.55,.30,.55,.60,.55]},
    LoraDRS:    {c:'#9d9d9d',v:[.60,.56,.40,.60,.60,.60]},
    TRC2:       {c:'#ff3b3b',v:[.98,.94,.92,.95,.96,.96]},
  };

  // Paper display numbers (best config)
  const disp={
    TRC2:[34.3,25.1,35.7,'59.0%',19.06,10.06],
  };

  const svg=document.getElementById('radarSvg');
  const N=axes.length, R=240;
  const enabled={};Object.keys(models).forEach(m=>enabled[m]=true);

  function pt(i,r){const a=-Math.PI/2+i*2*Math.PI/N;return{x:Math.cos(a)*r,y:Math.sin(a)*r};}

  function render(){
    svg.innerHTML='';
    // rings
    for(let k=1;k<=5;k++){
      const r=R*k/5;
      let d='';for(let i=0;i<N;i++){const p=pt(i,r);d+=(i?'L':'M')+p.x.toFixed(1)+','+p.y.toFixed(1);}d+='Z';
      const e=document.createElementNS('http://www.w3.org/2000/svg','path');
      e.setAttribute('d',d);e.setAttribute('fill','none');e.setAttribute('stroke','var(--line)');svg.appendChild(e);
    }
    // axes + labels
    for(let i=0;i<N;i++){
      const p=pt(i,R);
      const l=document.createElementNS('http://www.w3.org/2000/svg','line');
      l.setAttribute('x1',0);l.setAttribute('y1',0);l.setAttribute('x2',p.x);l.setAttribute('y2',p.y);
      l.setAttribute('stroke','var(--line)');svg.appendChild(l);
      const lp=pt(i,R+28);
      const t=document.createElementNS('http://www.w3.org/2000/svg','text');
      t.setAttribute('x',lp.x);t.setAttribute('y',lp.y);
      t.setAttribute('text-anchor','middle');t.setAttribute('dominant-baseline','middle');
      t.setAttribute('fill','var(--ink)');t.setAttribute('font-family','JetBrains Mono,monospace');
      t.setAttribute('font-size','10');t.setAttribute('font-weight','600');
      t.textContent=axes[i];svg.appendChild(t);
    }
    // polygons (sorted so TRC2 is on top)
    const keys=Object.keys(models).filter(m=>enabled[m]);
    keys.sort((a,b)=>(a==='TRC2'?1:0)-(b==='TRC2'?1:0));
    keys.forEach(m=>{
      const mdl=models[m];
      let d='';mdl.v.forEach((v,i)=>{const p=pt(i,R*v);d+=(i?'L':'M')+p.x.toFixed(1)+','+p.y.toFixed(1);});d+='Z';
      const f=document.createElementNS('http://www.w3.org/2000/svg','path');
      f.setAttribute('d',d);
      f.setAttribute('fill',mdl.c);
      f.setAttribute('fill-opacity',m==='TRC2'?.18:.08);
      f.setAttribute('stroke',mdl.c);
      f.setAttribute('stroke-width',m==='TRC2'?2.5:1);
      if(m==='TRC2')f.setAttribute('filter','drop-shadow(0 0 6px '+mdl.c+')');
      svg.appendChild(f);
      // vertex circles for TRC2
      if(m==='TRC2'){
        mdl.v.forEach((v,i)=>{
          const p=pt(i,R*v);
          const c=document.createElementNS('http://www.w3.org/2000/svg','circle');
          c.setAttribute('cx',p.x);c.setAttribute('cy',p.y);c.setAttribute('r',4);
          c.setAttribute('fill',mdl.c);svg.appendChild(c);
          if(disp.TRC2){
            const lp=pt(i,R*v+18);
            const tt=document.createElementNS('http://www.w3.org/2000/svg','text');
            tt.setAttribute('x',lp.x);tt.setAttribute('y',lp.y);
            tt.setAttribute('text-anchor','middle');tt.setAttribute('dominant-baseline','middle');
            tt.setAttribute('fill',mdl.c);tt.setAttribute('font-family','Instrument Serif,serif');
            tt.setAttribute('font-size','14');tt.setAttribute('font-weight','600');
            tt.textContent=disp.TRC2[i];svg.appendChild(tt);
          }
        });
      }
    });
  }

  // legend
  const leg=document.getElementById('radarLegend');
  Object.entries(models).forEach(([m,mdl])=>{
    const row=document.createElement('div');row.className='rm-row'+(m==='TRC2'?' trc2':'');
    row.innerHTML=`
      <span class="rm-sw" style="background:${mdl.c};${m==='TRC2'?'box-shadow:0 0 12px '+mdl.c:''}"></span>
      <span class="rm-name">${m==='TRC2'?'TRC² (ours)':m}</span>
      <span class="rm-scores">${disp[m]?disp[m].join(' · '):(mdl.v.reduce((a,b)=>a+b,0)/mdl.v.length*100|0)+'/100'}</span>
    `;
    row.addEventListener('click',()=>{enabled[m]=!enabled[m];row.classList.toggle('hide',!enabled[m]);render();});
    leg.appendChild(row);
  });

  render();
  addEventListener('themechange',render);
})();

/* ══════════════════════════════════════════════════════════════
   HEATMAP (native)
   ══════════════════════════════════════════════════════════════ */
(() => {
  // Heatmap endpoints are AUFC values at the last logged optimizer step for
  // each (model, ordering) run. Most runs go to step 22 000; three were
  // truncated (deepseek-WCG, falcon-WGC at 15k, moe-WCG at 20.5k) and use
  // the last logged value — flagged inline below.
  // Row order matches the visual table: descending by typical forgetting,
  // with TRC² pinned to the bottom for emphasis.
  const ROW_ORDER = ['LoraDRS','MoE','Mamba','FALCON','BlkAttnRes','DeepSeek','Transformer','TRC2'];

  // PPL endpoints — derived live from STREAM_DATA so this row stays in sync
  // with the chart data above. Final value of each series, rounded to 2 dp.
  const pplData = ROW_ORDER.map(model =>
    ['CGW','GCW','GWC','WCG','WGC'].map(order => {
      const series = STREAM_DATA[order][model];
      return Math.round(series[series.length - 1][1] * 100) / 100;
    })
  );

  // BLEU and Token-accuracy endpoints — extracted directly from the
  // matching `cl/bleu/aufc` and `cl/token_acc/aufc` CSVs.
  const bleuData = [
    [1.48, 7.57, 8.57, 2.03, 2.35],   // LoraDRS
    [1.01, 5.61, 6.00, 1.36, 1.98],   // MoE
    [1.20,10.74,11.06, 2.61, 2.90],   // Mamba
    [1.40,11.04,12.15, 2.44, 1.83],   // FALCON          (WGC truncated @ 15k)
    [0.41, 0.40, 0.40, 0.16, 0.31],   // BlkAttnRes
    [1.45, 8.61,11.24, 4.34, 2.32],   // DeepSeek        (WCG run goes to 22k)
    [1.48, 4.20, 5.47, 2.06, 2.38],   // Transformer
    [0.15, 0.10, 0.16, 0.12, 0.11],   // TRC²            (was 0.07 @ GCW; CSV gives 0.10)
  ];
  const tokData = [
    [0.37, 0.29, 0.31, 0.11, 0.20],   // LoraDRS
    [0.36, 0.26, 0.27, 0.08, 0.19],   // MoE             (WCG truncated @ 20.5k)
    [0.36, 0.38, 0.41, 0.14, 0.26],   // Mamba
    [0.32, 0.32, 0.34, 0.11, 0.11],   // FALCON          (WGC truncated @ 15k → carry-forward)
    [0.36, 0.21, 0.24, 0.10, 0.20],   // BlkAttnRes
    [0.35, 0.28, 0.32, 0.18, 0.20],   // DeepSeek        (WCG cell was 0.10; CSV gives 0.18)
    [0.37, 0.18, 0.25, 0.11, 0.20],   // Transformer
    [0.12, 0.07, 0.07, 0.06, 0.06],   // TRC²
  ];

  const ROW_LABELS = ROW_ORDER.map(m => m === 'TRC2' ? 'TRC² (ours)' : m);
  const metrics={
    ppl:{
      title:'Perplexity AUFC · lower is better',
      scale:[0,1.7],
      rows: ROW_LABELS,
      data: pplData,
    },
    bleu:{
      title:'BLEU AUFC · lower is better',
      scale:[0,12.5],
      rows: ROW_LABELS,
      data: bleuData,
    },
    tok:{
      title:'Token-accuracy AUFC · lower is better',
      scale:[0,0.42],
      rows: ROW_LABELS,
      data: tokData,
    },
  };
  const cols=['C→G→W','G→C→W','G→W→C','W→C→G','W→G→C'];
  const grid=document.getElementById('heatGrid');
  const title=document.getElementById('heatTitle');

  function color(v,min,max){
    const k=Math.max(0,Math.min(1,(v-min)/(max-min)));
    // cool → warm: blue → white → red
    if(k<.5){
      const kk=k*2;return `rgba(${Math.round(70+kk*160)},${Math.round(130+kk*110)},${Math.round(200-kk*80)},${.25+kk*.35})`;
    }else{
      const kk=(k-.5)*2;return `rgba(${Math.round(230)},${Math.round(240-kk*160)},${Math.round(200-kk*170)},${.60+kk*.30})`;
    }
  }

  function render(key){
    const m=metrics[key];
    title.textContent=m.title;
    grid.style.gridTemplateColumns=`140px repeat(${cols.length},minmax(70px,1fr))`;
    grid.innerHTML='';
    // header row
    grid.appendChild(cellEl('head','Model'));
    cols.forEach(c=>grid.appendChild(cellEl('head',c)));
    // data rows
    m.rows.forEach((rn,ri)=>{
      const isTRC=rn.includes('TRC²');
      grid.appendChild(cellEl('label'+(isTRC?' trc2-row':''),rn));
      m.data[ri].forEach(v=>{
        const e=document.createElement('div');
        e.className='hcell'+(isTRC?' trc2-row':'');
        e.style.background=color(v,m.scale[0],m.scale[1]);
        e.style.color=isTRC?'#fff':(v>m.scale[1]*.55?'#fff':'#0a0a14');
        e.style.fontWeight=isTRC?'700':'500';
        e.textContent=v.toFixed(2);
        grid.appendChild(e);
      });
    });
  }
  function cellEl(cls,tx){const e=document.createElement('div');e.className='hcell '+cls;e.textContent=tx;return e;}

  document.querySelectorAll('.heat-tabs .chip').forEach(b=>{
    b.addEventListener('click',()=>{
      document.querySelectorAll('.heat-tabs .chip').forEach(x=>x.classList.remove('active'));
      b.classList.add('active');render(b.dataset.metric);
    });
  });
  render('ppl');
  addEventListener('themechange',()=>{
    const act=document.querySelector('.heat-tabs .chip.active');
    render(act?act.dataset.metric:'ppl');
  });
})();

/* ══════════════════════════════════════════════════════════════
   ORDER ROULETTE
   ══════════════════════════════════════════════════════════════ */
(() => {
  // Derive from STREAM_DATA (the real recorded AUFC trajectories) so values
  // stay in sync with the CSVs and can never drift the way a hardcoded table can.
  const data = {};
  Object.entries(STREAM_DATA).forEach(([order, models]) => {
    const trc = models.TRC2[models.TRC2.length - 1][1];
    let bestM = null, bestV = Infinity;
    Object.entries(models).forEach(([m, series]) => {
      if (m === 'TRC2') return;
      const v = series[series.length - 1][1];
      if (v < bestV) { bestV = v; bestM = m; }
    });
    const adv = bestV / trc;
    const pct = Math.round((1 - trc / bestV) * 100);
    // Display name tweak: LoraDRS → LoRA-DRS reads better in the heading.
    const displayName = bestM === 'LoraDRS' ? 'LoRA-DRS'
                      : bestM === 'BlkAttnRes' ? 'BlkAttnRes'
                      : bestM;
    data[order] = { trc, base: bestV, baseName: displayName, adv, pct };
  });
  const maxVal=1.1;
  const ordTrc=document.getElementById('ordTrc'),ordBase=document.getElementById('ordBase');
  const ordTrcBar=document.getElementById('ordTrcBar'),ordBaseBar=document.getElementById('ordBaseBar');
  const ordAdvBig=document.getElementById('ordAdvBig'),ordAdvPct=document.getElementById('ordAdvPct');
  const ordBaseName=document.getElementById('ordBaseName');

  function show(k){
    const d=data[k];
    ordTrc.textContent=d.trc.toFixed(2);
    ordBase.textContent=d.base.toFixed(2);
    ordTrcBar.style.width=((d.trc/maxVal)*100)+'%';
    ordTrcBar.textContent=d.trc.toFixed(2);
    ordBaseBar.style.width=((d.base/maxVal)*100)+'%';
    ordBaseBar.textContent=d.base.toFixed(2);
    ordAdvBig.textContent=d.adv.toFixed(2)+'×';
    ordAdvPct.textContent=d.pct+'%';
    ordBaseName.textContent='Best baseline · '+d.baseName;
  }
  document.querySelectorAll('#orderChips .obtn').forEach(b=>{
    b.addEventListener('click',()=>{
      document.querySelectorAll('#orderChips .obtn').forEach(x=>x.classList.remove('active'));
      b.classList.add('active');show(b.dataset.o);
    });
  });
  show('CGW');
  addEventListener('themechange',()=>{
    const act=document.querySelector('.roul-tabs .chip.active');
    show(act?act.dataset.order:'CGW');
  });
})();

/* ══════════════════════════════════════════════════════════════
   ABLATION LAB
   ══════════════════════════════════════════════════════════════ */
(() => {
  // config -> {ppl, bleu, tok, curve(22k)}
  // From ablation figure: Both (TRC²), Thal only, Hippo only, Neither
  const configs={
    '11':{name:'Full TRC²',ppl:0.44,bleu:0.12,tok:0.08,end:0.44,color:'#ff3b3b',verdict:'Full TRC². Best retention profile across all three AUFC metrics — the configuration we ship.'},
    '10':{name:'Thal only',ppl:0.82,bleu:0.28,tok:0.17,end:0.82,color:'#fbbf24',verdict:'Thalamic routing alone. Low endpoint loss, but still drifts — lacks the episodic correction when tasks are revisited.'},
    '01':{name:'Hippo only',ppl:0.61,bleu:0.19,tok:0.12,end:0.61,color:'#c084fc',verdict:'Hippocampal memory alone. Retention holds but without thalamic gating, attention mixes everything — more interference.'},
    '00':{name:'Neither · MoE baseline',ppl:1.11,bleu:0.74,tok:0.13,end:1.11,color:'#9d9d9d',verdict:'Neither component. This is effectively the MoE backbone — classic catastrophic forgetting behavior.'},
  };
  const knobs={thal:true,hippo:true};
  const kt=document.getElementById('knobThal'),kh=document.getElementById('knobHippo');
  const labPpl=document.getElementById('labPpl'),labBleu=document.getElementById('labBleu'),labTok=document.getElementById('labTok');
  const labConfig=document.getElementById('labConfig'),labVerdict=document.getElementById('labVerdict');
  const canv=document.getElementById('labCanvas'),ctx=canv.getContext('2d');

  function key(){return (knobs.thal?'1':'0')+(knobs.hippo?'1':'0');}
  function resize(){
    const dpr=Math.min(2,devicePixelRatio||1);
    canv.width=canv.offsetWidth*dpr;canv.height=canv.offsetHeight*dpr;
    ctx.setTransform(dpr,0,0,dpr,0,0);
  }
  addEventListener('resize',resize);

  function render(){
    const k=key(),cfg=configs[k];
    labPpl.querySelector('.v').textContent=cfg.ppl.toFixed(2);
    labBleu.querySelector('.v').textContent=cfg.bleu.toFixed(2);
    labTok.querySelector('.v').textContent=cfg.tok.toFixed(2);
    labConfig.textContent=`thal ${knobs.thal?'✓':'✗'} · hippo ${knobs.hippo?'✓':'✗'} · ${cfg.name}`;
    labVerdict.textContent=cfg.verdict;
    // highlight best — only TRC² (11) lights up red
    [labPpl,labBleu,labTok].forEach(el=>el.classList.toggle('best',k==='11'));

    // curve
    const w=canv.offsetWidth,h=canv.offsetHeight;
    ctx.fillStyle = TRC_THEME.isDark ? '#0a0a14' : '#faf8f3';
    ctx.fillRect(0,0,w,h);
    const PAD={l:36,r:12,t:12,b:22};
    const W=w-PAD.l-PAD.r,H=h-PAD.t-PAD.b;
    // axis
    ctx.strokeStyle=TRC_THEME.grid;
    for(let y=0;y<=4;y++){const yy=PAD.t+H-y/4*H;ctx.beginPath();ctx.moveTo(PAD.l,yy);ctx.lineTo(PAD.l+W,yy);ctx.stroke();
      ctx.fillStyle=TRC_THEME.axisFaint;ctx.font='9px JetBrains Mono';ctx.textAlign='right';ctx.fillText((y*.4).toFixed(1),PAD.l-4,yy+3);}
    // boundary at Wiki→GSM (step 20k of 22k here we scale 10k→22k) — just render full curve
    // Draw all four for comparison but active emphasized
    Object.entries(configs).forEach(([kk,c])=>{
      ctx.beginPath();
      const N=120;
      for(let i=0;i<=N;i++){
        const t=i/N;
        const s=t*1; // normalized
        // smooth rising to endpoint, small bump mid
        const v=c.end*( (1-Math.exp(-s*3)) + .08*Math.sin(s*Math.PI) );
        const x=PAD.l+t*W;
        const y=PAD.t+H-Math.min(v,1.6)/1.6*H;
        i?ctx.lineTo(x,y):ctx.moveTo(x,y);
      }
      ctx.strokeStyle=c.color;
      ctx.lineWidth=kk===k?2.5:1;
      ctx.globalAlpha=kk===k?1:.3;
      if(kk===k){ctx.shadowColor=c.color;ctx.shadowBlur=8;}
      ctx.stroke();ctx.shadowBlur=0;ctx.globalAlpha=1;
    });
    // active endpoint marker
    const endY=PAD.t+H-Math.min(cfg.end,1.6)/1.6*H;
    ctx.fillStyle=cfg.color;ctx.beginPath();ctx.arc(PAD.l+W,endY,4,0,Math.PI*2);ctx.fill();
    // title strip
    ctx.fillStyle=TRC_THEME.axisFaint;ctx.font='9px JetBrains Mono';ctx.textAlign='left';
    ctx.fillText('10k → 22k · PPL AUFC',PAD.l,h-4);
  }

  kt.addEventListener('click',()=>{knobs.thal=!knobs.thal;kt.classList.toggle('on',knobs.thal);render();});
  kh.addEventListener('click',()=>{knobs.hippo=!knobs.hippo;kh.classList.toggle('on',knobs.hippo);render();});
  resize();render();
  addEventListener('themechange',render);
})();

